class Range implements Iterable<Integer> {
  int from, to;
  public Iterator<Integer> iterator(){
    return new Iterator<>(){
      int cur = from;
      public boolean hasNext(){ return cur < to; }
      public Integer next(){ return cur++; }
    };
  }
}

interface Visitor { void visit(Book b); void visit(Dvd d); }
interface Item { void accept(Visitor v); }
class Book implements Item {
  public void accept(Visitor v){ v.visit(this); }
}

class PizzaFactory {
  Pizza create(String type){
    if (type.equals("margherita")) return new Margherita();
    if (type.equals("pepperoni")) return new Pepperoni();
    return null;
  }
}

